"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[7448],{17891:e=>{e.exports=JSON.parse('{"functions":[{"name":"Destroy","desc":"Cleans up all connections used by the player handler.","params":[],"returns":[],"function_type":"method","source":{"line":101,"path":"src/Server/Classes/PlayerHandler/init.luau"}},{"name":"IsCharacterType","desc":"Returns whether the player handler is of the given [CharacterType].","params":[{"name":"characterType","desc":"","lua_type":"CharacterType"}],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":112,"path":"src/Server/Classes/PlayerHandler/init.luau"}},{"name":"OnTilt","desc":"Handles a tilt event from the client, sending the tilt angle to all clients.","params":[{"name":"angle","desc":"","lua_type":"number"}],"returns":[],"function_type":"method","source":{"line":122,"path":"src/Server/Classes/PlayerHandler/init.luau"}},{"name":"_init","desc":"Initializes the player handler with the given [Player], connecting to its character events.","params":[{"name":"instance","desc":"","lua_type":"Player"}],"returns":[],"function_type":"method","private":true,"source":{"line":138,"path":"src/Server/Classes/PlayerHandler/init.luau"}},{"name":"_onCharacterAdded","desc":"Handles the loading of the client\'s character, telling them to construct their character controller.","params":[{"name":"character","desc":"","lua_type":"Model"}],"returns":[],"function_type":"method","private":true,"source":{"line":160,"path":"src/Server/Classes/PlayerHandler/init.luau"}},{"name":"_onCharacterRemoving","desc":"Handles the removal of the client\'s character, ensuring `:_onDied` has been called.","params":[],"returns":[],"function_type":"method","private":true,"source":{"line":181,"path":"src/Server/Classes/PlayerHandler/init.luau"}},{"name":"_onDied","desc":"Handles character death, marking the player handler as dead and respawning the character.","params":[],"returns":[],"function_type":"method","private":true,"source":{"line":193,"path":"src/Server/Classes/PlayerHandler/init.luau"}}],"properties":[{"name":"Instance","desc":"The [Player] who is being handled by the player handler.","lua_type":"Player","source":{"line":42,"path":"src/Server/Classes/PlayerHandler/init.luau"}},{"name":"_characterType","desc":"The [CharacterType] of the [CharacterController] associated with the player handler.","lua_type":"CharacterType","private":true,"source":{"line":49,"path":"src/Server/Classes/PlayerHandler/init.luau"}},{"name":"_trove","desc":"The [Trove] used to manage the player handler\'s connections and resources.","lua_type":"Trove","private":true,"source":{"line":55,"path":"src/Server/Classes/PlayerHandler/init.luau"}},{"name":"_isAlive","desc":"Whether the player handler\'s character is alive.","lua_type":"boolean","private":true,"source":{"line":61,"path":"src/Server/Classes/PlayerHandler/init.luau"}}],"types":[],"name":"PlayerHandler","desc":"PlayerHandler is an abstract base class for managing a client\'s [CharacterController] on the server. \\nIt handles the lifecycle of the player\'s character, including character spawning, removal, and respawning upon death. \\nThis class also provides a foundation for subclasses to implement game-specific behavior, such as handling remote \\nevents and character logic.\\n\\n### Client Interaction:\\n- The `OnTilt` method broadcasts the tilt angle received from the client to all other clients using the `Tilt` \\n  [RemoteEvent]. This ensures that tilt animations are synchronized across the game.\\n- The `_onCharacterAdded` method fires the `Spawn` [RemoteEvent] to notify the client to construct their corresponding \\n  [CharacterController]. This keeps the client-side character logic aligned with the server.\\n- These interactions are vital for maintaining consistent state and behavior between the server and clients.\\n\\n### Highlights:\\n- Implements robust resource management using [Trove] to clean up connections and resources when the player leaves.\\n- Provides hooks (`:_onCharacterAdded`, `:_onCharacterRemoving`, `:_onDied`) for subclasses to add custom behavior \\n  during character lifecycle events.\\n- Ensures seamless respawn mechanics with a configurable respawn delay.\\n\\nThis class is abstract and should not be instantiated directly. Instead, it should be extended to define specific \\ncharacter types and game logic.","tags":["Abstract"],"realm":["Server"],"source":{"line":88,"path":"src/Server/Classes/PlayerHandler/init.luau"}}')}}]);